/**
 * harmony-postinstall.js - 鸿蒙项目后处理脚本
 *
 * 修复 RNOH codegen 类型缺失问题
 * 兼容平台: macOS, Windows, Linux
 */

const fs = require('fs');
const path = require('path');

/**
 * 生成 RNOH codegen stub 类型定义
 */
function generateRNCodePushStub() {
  return `/**
 * Stub for RNOH codegen types
 *
 * This file provides type definitions for third-party TurboModules
 * (like RTNCodePush) that would normally be generated by RNOH codegen.
 *
 * Issue: @react-native-oh-tpl/react-native-code-push references
 * @rnoh/react-native-openharmony/generated/ts which doesn't exist.
 */

import type { TurboModule } from '@rnoh/react-native-openharmony/src/main/ets/RNOH/ts';

// Codegen-generated TM namespace stub
export declare namespace TM {
  export namespace RTNCodePush {
    const NAME: string;
    export interface Spec extends TurboModule {
      sync(): Promise<unknown>;
      downloadUpdate(updatePackage: Record<string, any>, notifyProgress: boolean): Promise<void>;
      isFailedUpdate(packageHash: string): Promise<boolean>;
      getConfiguration(): Promise<object>;
      getUpdateMetadata(updateState: number): Promise<object | null>;
      getNewStatusReport(): Promise<object>;
      installUpdate(
        updatePackage: Record<string, any>,
        installMode: number,
        minimumBackgroundDuration: number
      ): Promise<void>;
      disallow(): Promise<unknown>;
      clearPendingRestart(): Promise<unknown>;
      restartApp(onlyIfUpdateIsPending: boolean): Promise<null>;
      setLatestRollbackInfo(packageHash: string): Promise<string | null>;
      isFirstRun(packageHash: string): Promise<boolean | null>;
      recordStatusReported(statusReport: Record<string, any>): Promise<void>;
      saveStatusReportForRetry(statusReport: Record<string, any>): Promise<void>;
      downloadAndReplaceCurrentBundle(remoteBundleUrl: string): Promise<void>;
      allow(): Promise<unknown>;
      notifyApplicationReady(): Promise<string>;
      clearUpdates(): Promise<void>;
      getBundle(path: string): Promise<ArrayBuffer>;
      getLatestRollbackInfo(): Promise<string | null>;
    }
  }
}
`;
}

/**
 * 在指定目录创建 generated/ts.ts stub 文件
 */
function createGeneratedStub(baseDir) {
  const generatedDir = path.join(baseDir, 'generated');
  const stubPath = path.join(generatedDir, 'ts.ts');

  // 创建 generated 目录
  if (!fs.existsSync(generatedDir)) {
    fs.mkdirSync(generatedDir, { recursive: true });
  }

  // 检查是否已存在有效 stub
  if (fs.existsSync(stubPath)) {
    const content = fs.readFileSync(stubPath, 'utf8');
    if (content.includes('TM.RTNCodePush')) {
      console.log(`[harmony-postinstall] Stub already exists at ${stubPath}`);
      return;
    }
  }

  // 写入 stub 文件
  fs.writeFileSync(stubPath, generateRNCodePushStub(), 'utf8');
  console.log(`[harmony-postinstall] Created RNOH codegen stub: ${stubPath}`);
}

/**
 * 扫描并修复所有 RNOH 包
 */
function fixRNOHPackages(harmonyRoot) {
  const ohModulesDir = path.join(harmonyRoot, 'oh_modules');

  if (!fs.existsSync(ohModulesDir)) {
    console.log('[harmony-postinstall] oh_modules directory not found');
    return;
  }

  // 1. 在顶层 @rnoh 目录创建 stub（如果存在）
  const topLevelRNOH = path.join(ohModulesDir, '@rnoh/react-native-openharmony');
  if (fs.existsSync(topLevelRNOH)) {
    createGeneratedStub(topLevelRNOH);
  }

  // 2. 扫描 .ohpm 目录中的所有 @rnoh/react-native-openharmony 副本
  const ohpmDir = path.join(ohModulesDir, '.ohpm');
  if (fs.existsSync(ohpmDir)) {
    const entries = fs.readdirSync(ohpmDir, { withFileTypes: true });
    for (const entry of entries) {
      if (entry.isDirectory() && entry.name.startsWith('@rnoh+react-native-openharmony@')) {
        const packageOhModules = path.join(ohpmDir, entry.name, 'oh_modules/@rnoh/react-native-openharmony');
        if (fs.existsSync(packageOhModules)) {
          createGeneratedStub(packageOhModules);
        }
      }
    }
  }
}

/**
 * 主函数
 */
function main() {
  const rootDir = path.resolve(__dirname, '..');
  const harmonyRoot = path.join(rootDir, 'apps/oa/harmony');

  // 检查是否在鸿蒙项目中
  const packageJsonPath = path.join(harmonyRoot, 'oh-package.json5');
  if (!fs.existsSync(packageJsonPath)) {
    console.log('[harmony-postinstall] Harmony project not found, skipping');
    return;
  }

  console.log('[harmony-postinstall] Running RNOH codegen stub fix...');
  fixRNOHPackages(harmonyRoot);
  console.log('[harmony-postinstall] Done');
}

main();
